# GRAFICOSimport matplotlib.pyplot as pltfrom src.perfiles import Clientedef grafico_compra_por_fidelizacion(df):    '''    Genera un gráfico de barras que muestra el monto de compra    promedio para cada nivel de fidelización.    Parameters    ----------    df : DataFrame        DataFrame validado con los datos de clientes.    Returns    -------    None.    '''    datos = df.groupby("loyalty_status")["purchase_amount"].mean()    plt.figure(figsize=(8, 5))    plt.bar(datos.index, datos.values)    plt.title("Compra promedio según fidelización")    plt.xlabel("Nivel de fidelización")    plt.ylabel("Monto de compra promedio")    plt.tight_layout()    plt.show()def grafico_distribucion_perfiles(df):    '''    Genera un gráfico de barras con la cantidad de clientes    pertenecientes a cada perfil.        ¿Cómo lo hace? Recorro el DataFrame,    creo un objeto Cliente para cada fila,    uso el método clasificar() de perfiles.py,    guardo cada categoría obtenida,    cuento cuántos clientes pertenecen a cada perfil    y finalmente genero el gráfico.    Los perfiles posibles son:    - Premium    - Frecuente    - Ocasional    Parameters    ----------    df : DataFrame        DataFrame validado con los datos de clientes.    Returns    -------    None.    '''    perfiles = []    for _, fila in df.iterrows():        cliente = Cliente(            fila["id"],            fila["age"],            fila["income"],            fila["purchase_frequency"],            fila["purchase_amount"],            fila["satisfaction_score"]        )        categoria = cliente.clasificar_perfil()        perfiles.append(categoria)    conteo = {}    for perfil in perfiles:        if perfil not in conteo:            conteo[perfil] = 1        else:            conteo[perfil] += 1    plt.figure(figsize=(8, 5))    plt.bar(conteo.keys(), conteo.values())    plt.title("Distribución de perfiles de clientes")    plt.xlabel("Perfil")    plt.ylabel("Cantidad de clientes")    plt.tight_layout()    plt.show()def mostrar_menu_graficos(df):    '''    Muestra las opciones de gráficos disponibles y ejecuta    el gráfico seleccionado por el usuario.    Parameters    ----------    df : DataFrame        DataFrame validado con los datos de clientes.    Returns    -------    None.    '''    print("\nGRÁFICOS DISPONIBLES")    print("1. Compra promedio según fidelización")    print("2. Distribución de perfiles")    while True:        try:            opcion = int(input("\nSeleccione una opción: "))            if opcion not in [1, 2]:                print("Error: debe ingresar una opción válida")                continue            break        except ValueError:            print("Error: debe ingresar un número entero")    if opcion == 1:        grafico_compra_por_fidelizacion(df)    elif opcion == 2:        grafico_distribucion_perfiles(df)